## 🐛 Bug Report

`workbook.xslx.writeFile('filename.xslx')` fails for large files potentially because it attempts to write the entire worksheet at once - https://github.com/exceljs/exceljs/blob/master/lib/xlsx/xlsx.js#L641
Maybe we should consider writing the rows in chunks and wait for the `zip` stream to drain before writing data to it which can potentially help us to avoid heap out of memory issues.

Lib version: 4.4.0

## Steps To Reproduce
Fails for massively large files. Exact data cannot be provided.

## The expected behaviour:

<!-- A clear and concise description of what you expected to happen. -->


## Possible solution (optional, but very helpful):

```javascript
  async writeWorksheetRowsInChunks(worksheet, xmlStream, zip, worksheetXform) {
    const chunkSize = 1000;
    const rows = worksheet.getRows();
    let currentRow = 1;
  
    while (currentRow <= rows.length) {
      const chunk = rows.slice(currentRow - 1, currentRow - 1 + chunkSize);
      
      // Add the chunk of rows to the worksheet - you may need to tweak render method to support this
      worksheetXform.render(xmlStream, worksheet, chunk);
      
      // Append the XML stream to the zip file
      zip.append(xmlStream.xml, { name: `xl/worksheets/sheet${worksheet.id}.xml` });

      // Increment the currentRow for the next chunk
      currentRow += chunkSize;

      // wait for the zip stream to drain to avoid memory issues
      await new Promise((resolve, _) => {
        zip.on('drain', () => {
          resolve();
        });
      });
    }
  }

  async addWorksheets(zip, model) {
    // preparation phase
    const worksheetXform = new WorksheetXform();
    const relationshipsXform = new RelationshipsXform();
    const commentsXform = new CommentsXform();
    const vmlNotesXform = new VmlNotesXform();

    // write sheets
    model.worksheets.forEach(worksheet => {
      let xmlStream = new XmlStream();
      this.writeWorksheetRowsInChunks(worksheet, xmlStream, zip, worksheetXform);

      if (worksheet.rels && worksheet.rels.length) {
        xmlStream = new XmlStream();
        relationshipsXform.render(xmlStream, worksheet.rels);
        zip.append(xmlStream.xml, {name: `xl/worksheets/_rels/sheet${worksheet.id}.xml.rels`});
      }

      if (worksheet.comments.length > 0) {
        xmlStream = new XmlStream();
        commentsXform.render(xmlStream, worksheet);
        zip.append(xmlStream.xml, {name: `xl/comments${worksheet.id}.xml`});

        xmlStream = new XmlStream();
        vmlNotesXform.render(xmlStream, worksheet);
        zip.append(xmlStream.xml, {name: `xl/drawings/vmlDrawing${worksheet.id}.vml`});
      }
    });
  }

```
